// Nümunə: DOM manipulyasiyası
// HTML: <div id="outfitElement" class="summer" data-style="modern">Qəşəng köynək</div>
const outfitElement = document.getElementById("outfitElement");

// Məzmun dəyişdirmə
outfitElement.innerText = "Yeni köynək";

// Sinif əlavə etmə
outfitElement.classList.add("trendy");

// Atribut dəyişdirmə
outfitElement.setAttribute("data-style", "classic");

// Yeni element yaratma və əlavə etmə
const newOutfit = document.createElement("div");
newOutfit.textContent = "Yeni şalvar";
newOutfit.className = "casual";
document.body.appendChild(newOutfit);

// Stil dəyişdirmə
outfitElement.style.color = "red";

// Hadisə əlavə etmə
outfitElement.addEventListener("click", () => {
  outfitElement.classList.toggle("highlight");
});

// Element silmə
// newOutfit.remove();

