// Öz DOM manipulyasiya nümunəni yarat!
const outfitElement = document.createElement("div");
outfitElement.textContent = "Stilli köynək";
outfitElement.className = "trendy";
document.body.appendChild(outfitElement);

outfitElement.addEventListener("click", () => {
  outfitElement.classList.toggle("highlight");
  outfitElement.style.backgroundColor = outfitElement.classList.contains("highlight") ? "yellow" : "white";
});

